import { AppShell } from "@/components/app-shell";
import { BoardForm } from "@/components/board/board-form";
import { getAuthContext } from "@/lib/firebase/auth";
import { boardsRepository } from "@/lib/repositories/boards-repository";

export default async function Page() {
  const auth = await getAuthContext();
  if (!auth?.workspaceId) {
    return <AppShell title="Board"><p>Sessão não encontrada.</p></AppShell>;
  }

  const boards = await boardsRepository.list(auth.workspaceId);

  return (
    <AppShell title="Board">
      <section className="rounded border bg-white p-4"><BoardForm /></section>
      <section className="space-y-3">
        {boards.map((board) => (
          <article key={board.id} className="rounded border bg-white p-4">
            <h2 className="font-semibold">{board.title}</h2>
            <p className="text-sm text-gray-600">{board.description || "Sem descrição."}</p>
          </article>
        ))}
        {boards.length === 0 ? <p className="rounded border bg-white p-4 text-sm text-gray-600">Nenhuma entrada no board.</p> : null}
      </section>
    </AppShell>
  );
}
